it('does not incorrectly match optional-param-with-suffix when navigating to required param sibling', () => {
  // Regression test for:
  // "Navigating on the Client from optional Param with static Suffix to required Param Index matches wrong Parent"
  //
  // Given two sibling routes:
  // - /admin-levels/{-$adminLevelId}/reports  (optional param)
  // - /admin-levels/$adminLevelId/reports    (required param)
  // Matching /admin-levels/123/reports should prefer the required param route,
  // meaning the optional param route should NOT match this path.

  const basepath = '/'
  const input = '/admin-levels/123/reports'

  const optionalPattern = '/admin-levels/{-$adminLevelId}/reports'
  const requiredPattern = '/admin-levels/$adminLevelId/reports'

  // Optional pattern should fail to match because the upcoming required $adminLevelId
  // is the better candidate for consuming the "123" segment.
  expect(matchPathname(basepath, input, { to: optionalPattern })).toBeUndefined()

  // Required pattern should match as expected.
  expect(matchPathname(basepath, input, { to: requiredPattern })).toEqual({
    adminLevelId: '123',
  })
})

